     public void Register<T>(T service) where T : class
     {
         ArgumentNullException.ThrowIfNull(service);
         _services[typeof(T)] = service;
     }

     public T? Resolve<T>() where T : class =>
         _services.TryGetValue(typeof(T), out var svc) ? (T)svc : null;

